var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"나리!! 옥상에서 구경만 하지 말고 나리 친구들 좀 보내 줘! 어서!","JPN":"旦那！！　屋上で見てないでお仲間を送ってくれ！　早く！","ENG":"Hey!! Don’t just stand there and watch! Send your friends down! Come on!","TWN":"姊！你別只是在屋頂上看熱鬧，快派你的朋友來啊！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그 망할 년이 자꾸 어디선가 튀어나와서 뒤통수를 친다고! 이러다 우리 애들 다 죽겠어!","JPN":"あのクソ女がしきりにどこかから不意打ちしてきやがる！　このままじゃうちの奴ら全部死ぬぞ！","ENG":"That damn girl is going to reappear out of nowhere and get us all! At this rate we’re all die!","TWN":"那該死的女人一直不知道從哪裡冒出來，殺我們個措手不及！再這樣下去我們會全軍覆沒的!"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"기다려. 지금 부른 참이니까.","JPN":"待っていろ。今呼んだ。","ENG":"Hold on. I’m calling for someone.","TWN":"等等，我正打算要派人過去。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……! 설마 우릴 미끼로 쓴 건 아니겠지?","JPN":"へ、へへ……！　まさか俺らをエサにしたんじゃないだろうな？","ENG":"Hey, hey...! Don’t tell me you’re using us as bait?","TWN":"嘿嘿嘿……！你該不會是拿我們當誘餌吧？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그러다 나리도 죽어. 나리도 죽일 거라고, 응?","JPN":"それじゃ旦那も死ぬよ。俺が殺すから、な？","ENG":"You’ll die too, you know! You hear me?","TWN":"這樣姊也會沒命的！因為我會殺掉姊！知道嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"나한테 한눈 팔 시간이 있던가? 허세 부리지 말고 네 할일이나 잘 챙겨.","JPN":"私を見ている暇があるのか？　強がってないで自分の仕事にでも集中しろ。","ENG":"Is this really the proper time for this? Shouldn’t you be focusing on something else? Stop wasting time and take care of business.","TWN":"你有時間分心跟我說這些嗎？少在那邊虛張聲勢，把你該做的事做好！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래. 한눈 팔면 이렇게 뒤통수에 총구가 닿거든.","JPN":"そうそう。よそ見してるとこうやって頭に銃口が来ちゃうものね。","ENG":"My words exactly. If you focus on the wrong things even for a moment, you could end up just like this.","TWN":"沒錯，分心的話，就會像這樣被人拿槍指著後腦勺。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"방금 그 목소리 뭐야, 나리? 그 년이야?","JPN":"今の声はなんだ、旦那？　あの女か？","ENG":"Hey what was that noise just now? Was it the girl?","TWN":"剛剛那是什麼聲音？是那女的嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"설마 나리한테 갔어? 그 년은 우리 아빠를 죽인 년이야! 손대면 가만 안 둬!!","JPN":"まさか旦那のところに行ったのか？　あの女は俺のおやじを殺した女だ！　手を出したら許さねえぞ！","ENG":"No way, she got you too? She killed my father! I won’t let her get away with this!!","TWN":"她在姊那裡嗎？那女的是我的殺父仇人！我要親手解決她！不准你碰她！！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"이봐! 야!! 야 이 개──!!","JPN":"オイ！　こら！！　このクソ――！！","ENG":"Hey! Hey!! You fxx─!!","TWN":"喂！喂！你這該死的臭──！！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"나를 어떻게 찾았지?","JPN":"どうやって私を見つけた？","ENG":"How did you find me?","TWN":"你是怎麼找到我的？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"파레마에서 봤을 때부터 줄곧 마음에 걸렸거든.","JPN":"パレマで見かけた時からずっとひっかかってたの。","ENG":"You know, something’s been on my mind ever since I saw you in Parema.","TWN":"自從在波雷馬見到你後，我就一直放在心上。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"자크가 죽었다고 저렇게 미쳐 날뛸 부하들은 그 날 대부분 처리했어.","JPN":"ジャックが死んだからってあんな風に暴れそうな部下は、あの日ほとんど始末したから。","ENG":"I've dealt with most of Jacques's men who could go mad for his death that day.","TWN":"札克死掉那天，我明明就已經把大部分的手下都處理掉了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러면 누군가 저들을 선동했다는 거겠지. 약물로 정신을 흐트러뜨린 채로.","JPN":"そうだとしたら誰かがあいつらを煽ったってこと。薬で精神を乱してね。","ENG":"Someone must have made them behave that way. After drugging them.","TWN":"也就是說一定是有人煽動其餘的人，用藥物控制他們。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_SNIPER","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_SNIPER","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"파레마에서 저격할 때도 날 저격한 사람이 너였지?","JPN":"パレマで狙撃した時に私を狙ったのも君だったのね？","ENG":"You were the one who shot at me in Parema, right?","TWN":"在波雷馬的時候，狙擊我的人就是你吧？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"누구 명령으로 이러는지 대답해, 꼬마.","JPN":"誰の命令で動いてるのか答えなさい、ガキ。","ENG":"Tell me. Who gave you the order, kid?","TWN":"是誰指使你的？回答我，小鬼！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};